   122→
   123→// mountFS mounts the BPFFS filesystem into the desired mapRoot directory.
   124→func mountFS(logger *slog.Logger, printWarning bool) error {
   125→	if printWarning {
   126→		logger.Warn("================================= WARNING ==========================================")
   127→		logger.Warn("BPF filesystem is not mounted. This will lead to network disruption when Cilium pods")
   128→		logger.Warn("are restarted. Ensure that the BPF filesystem is mounted in the host.")
   129→		logger.Warn("https://docs.cilium.io/en/stable/operations/system_requirements/#mounted-ebpf-filesystem")
   130→		logger.Warn("====================================================================================")
   131→	}
   132→
   133→	logger.Info("Mounting BPF filesystem", logfields.BPFFSRoot, bpffsRoot)
   134→
   135→	mapRootStat, err := os.Stat(bpffsRoot)
   136→	if err != nil {
   137→		if os.IsNotExist(err) {
   138→			if err := MkdirBPF(bpffsRoot); err != nil {
   139→				return fmt.Errorf("unable to create bpf mount directory: %w", err)
   140→			}
   141→		} else {
   142→			return fmt.Errorf("failed to stat the mount path %s: %w", bpffsRoot, err)
   143→
   144→		}
   145→	} else if !mapRootStat.IsDir() {
   146→		return fmt.Errorf("%s is a file which is not a directory", bpffsRoot)
   147→	}
   148→
   149→	if err := unix.Mount(bpffsRoot, bpffsRoot, "bpf", 0, ""); err != nil {
   150→		return fmt.Errorf("failed to mount %s: %w", bpffsRoot, err)
   151→	}
   152→	return nil
   153→}
   154→
   155→// hasMultipleMounts checks whether the current mapRoot has only one mount.
   156→func hasMultipleMounts() (bool, error) {
   157→	num := 0
   158→
   159→	mountInfos, err := mountinfo.GetMountInfo()
   160→	if err != nil {
   161→		return false, err
   162→	}
   163→
   164→	for _, mountInfo := range mountInfos {
   165→		if mountInfo.Root == "/" && mountInfo.MountPoint == bpffsRoot {
   166→			num++
   167→		}
   168→	}
   169→
   170→	return num > 1, nil
   171→}
