   173→// checkOrMountCustomLocation tries to check or mount the BPF filesystem in the
   174→// given path.
   175→func checkOrMountCustomLocation(logger *slog.Logger, bpfRoot string) error {
   176→	setBPFFSRoot(bpfRoot)
   177→
   178→	// Check whether the custom location has a BPFFS mount.
   179→	mounted, bpffsInstance, err := mountinfo.IsMountFS(mountinfo.FilesystemTypeBPFFS, bpfRoot)
   180→	if err != nil {
   181→		return err
   182→	}
   183→
   184→	// If the custom location has no mount, let's mount BPFFS there.
   185→	if !mounted {
   186→		setBPFFSRoot(bpfRoot)
   187→		if err := mountFS(logger, true); err != nil {
   188→			return err
   189→		}
   190→
   191→		return nil
   192→	}
   193→
   194→	// If the custom location already has a mount with some other filesystem than
   195→	// BPFFS, return the error.
   196→	if !bpffsInstance {
   197→		return fmt.Errorf("mount in the custom directory %s has a different filesystem than BPFFS", bpfRoot)
   198→	}
   199→
   200→	logger.Info("Detected mounted BPF filesystem", logfields.BPFFSRoot, bpffsRoot)
   201→
   202→	return nil
   203→}
   204→
   205→// checkOrMountDefaultLocations tries to check or mount the BPF filesystem in
   206→// standard locations, which are:
   207→// - /sys/fs/bpf
   208→// - /run/cilium/bpffs
   209→// There is a procedure of determining which directory is going to be used:
   210→//  1. Checking whether BPFFS filesystem is mounted in /sys/fs/bpf.
   211→//  2. If there is no mount, then mount BPFFS in /sys/fs/bpf and finish there.
   212→//  3. If there is a BPFFS mount, finish there.
   213→//  4. If there is a mount, but with the other filesystem, then it means that most
   214→//     probably Cilium is running inside container which has mounted /sys/fs/bpf
   215→//     from host, but host doesn't have proper BPFFS mount, so that mount is just
   216→//     the empty directory. In that case, mount BPFFS under /run/cilium/bpffs.
   217→func checkOrMountDefaultLocations(logger *slog.Logger) error {
   218→	// Check whether /sys/fs/bpf has a BPFFS mount.
   219→	mounted, bpffsInstance, err := mountinfo.IsMountFS(mountinfo.FilesystemTypeBPFFS, bpffsRoot)
   220→	if err != nil {
   221→		return err
   222→	}
   223→
   224→	// If /sys/fs/bpf is not mounted at all, we should mount
   225→	// BPFFS there.
   226→	if !mounted {
   227→		if err := mountFS(logger, false); err != nil {
   228→			return err
   229→		}
   230→
   231→		return nil
   232→	}
   233→
   234→	if !bpffsInstance {
   235→		// If /sys/fs/bpf has a mount but with some other filesystem
   236→		// than BPFFS, it means that Cilium is running inside container
   237→		// and /sys/fs/bpf is not mounted on host. We should mount BPFFS
   238→		// in /run/cilium/bpffs automatically. This will allow operation
   239→		// of Cilium but will result in unmounting of the filesystem
   240→		// when the pod is restarted. This in turn will cause resources
   241→		// such as the connection tracking table of the BPF programs to
   242→		// be released which will cause all connections into local
   243→		// containers to be dropped. User is going to be warned.
   244→		logger.Warn(fmt.Sprintf("BPF filesystem is going to be mounted automatically "+
   245→			"in %s. However, it probably means that Cilium is running "+
   246→			"inside container and BPFFS is not mounted on the host. "+
   247→			"for more information, see: https://cilium.link/err-bpf-mount",
   248→			defaults.BPFFSRootFallback,
   249→		),
   250→		)
   251→		setBPFFSRoot(defaults.BPFFSRootFallback)
   252→
   253→		cMounted, cBpffsInstance, err := mountinfo.IsMountFS(mountinfo.FilesystemTypeBPFFS, bpffsRoot)
   254→		if err != nil {
   255→			return err
   256→		}
   257→		if !cMounted {
   258→			if err := mountFS(logger, false); err != nil {
   259→				return err
   260→			}
   261→		} else if !cBpffsInstance {
   262→			logging.Fatal(logger, fmt.Sprintf("%s is mounted but has a different filesystem than BPFFS", defaults.BPFFSRootFallback))
   263→		}
   264→	}
   265→
   266→	logger.Info("Detected mounted BPF filesystem", logfields.BPFFSRoot, bpffsRoot)
   267→
   268→	return nil
   269→}
   270→
   271→func checkOrMountFS(logger *slog.Logger, bpfRoot string) error {
   272→	if bpfRoot == "" || bpfRoot == defaults.BPFFSRoot {
   273→		if err := checkOrMountDefaultLocations(logger); err != nil {
   274→			return err
   275→		}
   276→	} else {
   277→		if err := checkOrMountCustomLocation(logger, bpfRoot); err != nil {
   278→			return err
   279→		}
   280→	}
   281→
   282→	multipleMounts, err := hasMultipleMounts()
   283→	if err != nil {
   284→		return err
   285→	}
   286→	if multipleMounts {
   287→		return fmt.Errorf("multiple mount points detected at %s", bpffsRoot)
   288→	}
   289→
   290→	return nil
   291→}
   292→
   293→// CheckOrMountFS checks or mounts the BPF filesystem and then
   294→// opens/creates/deletes all maps which have previously been scheduled to be
   295→// opened/created/deleted.
   296→//
   297→// If printWarning is set, will print a warning if bpffs has not previously been
   298→// mounted.
   299→func CheckOrMountFS(logger *slog.Logger, bpfRoot string) {
   300→	mountOnce.Do(func() {
   301→		if err := checkOrMountFS(logger, bpfRoot); err != nil {
   302→			logging.Fatal(logger, "Unable to mount BPF filesystem", logfields.Error, err)
   303→		}
   304→	})
   305→}
